-- FARM POSITION TAB
local SpotLeft  = Tabs.Spot:AddLeftGroupbox("위치 덮어쓰기 ")
local SpotRight = Tabs.Spot:AddRightGroupbox("빠른 저장 키 ")

local overrideLabel = SpotLeft:AddLabel({ Text = "사용자 지정 위치: 꺼짐 " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "저장됨: 없음 " })

SpotLeft:AddButton("현재 위치 저장 ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="오류 ", Description="캐릭터가 없습니다! ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="오류 ", Description="HumanoidRootPart가 없습니다! ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="위치가 저장되었습니다! ", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("사용자 지정 위치 지우기 ", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("저장됨: 없음 ")
    Library:Notify({Title="지움 ", Description="원래 캡처한 위치를 사용합니다. ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

local keybindLabel = SpotRight:AddLabel({ Text = "빠른 저장 키: F " })

SpotRight:AddButton("빠른 저장 키 설정 ", function()
